package com.itc.healthtrack.controllers;

import com.itc.healthtrack.dao.UserDAO;
import com.itc.healthtrack.models.User;
import javafx.application.Platform;
import javafx.event.ActionEvent;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Node;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextField;
import javafx.stage.Stage;

import java.io.IOException;

/**
 * Controlador para la pantalla de inicio de sesion.
 */
public class LoginController {

    // Vinculacion de las variables con los componentes visuales del FXML
    @FXML private TextField emailField;
    @FXML private PasswordField passwordField;
    @FXML private Label errorLabel;
    @FXML private Button loginButton;

    private final UserDAO userDAO = new UserDAO();

    /**
     * Metodo que se ejecuta al presionar el boton "Sign In".
     */
    @FXML
    protected void onLoginButtonClick(ActionEvent event) {
        String email = emailField.getText();
        String password = passwordField.getText();

        // Validacion basica de campos vacios
        if (email.isEmpty() || password.isEmpty()) {
            showError("Por favor, ingresa correo y contraseña.");
            return;
        }

        // Se deshabilita el boton para evitar multiples clics mientras se conecta a Firebase
        loginButton.setDisable(true);
        errorLabel.setVisible(false);

        // Se crea un hilo secundario para no congelar la interfaz grafica durante la conexion
        new Thread(() -> {
            try {
                // Se busca al usuario por correo
                User currentUser = userDAO.authenticateByEmail(email);

                Platform.runLater(() -> {
                    if (currentUser != null) {
                        // Si existe, se carga el panel principal (Dashboard)
                        loadDashboard(event, currentUser);
                    } else {
                        showError("Usuario no encontrado.");
                        loginButton.setDisable(false);
                    }
                });
            } catch (Exception e) {
                Platform.runLater(() -> {
                    showError("Error de conexion con la base de datos.");
                    loginButton.setDisable(false);
                });
            }
        }).start();
    }

    /**
     * Muestra un mensaje de error en la interfaz.
     */
    private void showError(String message) {
        errorLabel.setText(message);
        errorLabel.setVisible(true);
    }

    /**
     * Cambia la escena actual a la del Dashboard principal.
     */
    private void loadDashboard(ActionEvent event, User user) {
        try {
            FXMLLoader fxmlLoader = new FXMLLoader(getClass().getResource("/com/itc/healthtrack/views/dashboard-view.fxml"));
            Scene dashboardScene = new Scene(fxmlLoader.load(), 1000, 700);

            // Pasar la informacion del usuario al nuevo controlador (se creara despues)
            DashboardController controller = fxmlLoader.getController();
            controller.initData(user);

            // Obtener la ventana (Stage) actual y cambiar su escena
            Stage stage = (Stage) ((Node) event.getSource()).getScene().getWindow();
            stage.setScene(dashboardScene);
            stage.centerOnScreen();
        } catch (IOException e) {
            e.printStackTrace();
            showError("Error al cargar la interfaz principal.");
        }
    }
}

package com.itc.healthtrack.controllers;

import com.itc.healthtrack.dao.UserDAO;
import com.itc.healthtrack.models.User;
import javafx.application.Platform;
import javafx.event.ActionEvent;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Node;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextField;
import javafx.stage.Stage;

import java.io.IOException;

/**
 * Controlador para la pantalla de inicio de sesion.
 */
public class LoginController {

    // Vinculacion de las variables con los componentes visuales del FXML
    @FXML private TextField emailField;
    @FXML private PasswordField passwordField;
    @FXML private Label errorLabel;
    @FXML private Button loginButton;

    // Se inicializa bajo demanda para que fallos de Firebase no rompan la carga del FXML.
    private UserDAO userDAO;

    /**
     * Metodo que se ejecuta al presionar el boton "Sign In".
     */
    @FXML
    protected void onLoginButtonClick(ActionEvent event) {
        String email = emailField.getText();
        String password = passwordField.getText();

        // Validacion basica de campos vacios
        if (email.isEmpty() || password.isEmpty()) {
            showError("Por favor, ingresa correo y contraseña.");
            return;
        }

        // Se deshabilita el boton para evitar multiples clics mientras se conecta a Firebase
        loginButton.setDisable(true);
        errorLabel.setVisible(false);

        // Se crea un hilo secundario para no congelar la interfaz grafica durante la conexion
        new Thread(() -> {
            try {
                if (userDAO == null) {
                    userDAO = new UserDAO();
                }

                // Se busca al usuario por correo
                User currentUser = userDAO.authenticateByEmail(email);

                Platform.runLater(() -> {
                    if (currentUser != null) {
                        // Si existe, se carga el panel principal (Dashboard)
                        loadDashboard(event, currentUser);
                    } else {
                        showError("Usuario no encontrado.");
                        loginButton.setDisable(false);
                    }
                });
            } catch (Exception e) {
                Platform.runLater(() -> {
                    showError("Error de conexion con Firebase o credenciales invalidas.");
                    loginButton.setDisable(false);
                });
            }
        }).start();
    }

    /**
     * Muestra un mensaje de error en la interfaz.
     */
    private void showError(String message) {
        errorLabel.setText(message);
        errorLabel.setVisible(true);
    }

    /**
     * Cambia la escena actual a la del Dashboard principal.
     */
    private void loadDashboard(ActionEvent event, User user) {
        try {
            FXMLLoader fxmlLoader = new FXMLLoader(getClass().getResource("/com/itc/healthtrack/views/dashboard-view.fxml"));
            Scene dashboardScene = new Scene(fxmlLoader.load(), 1000, 700);

            // Pasar la informacion del usuario al nuevo controlador (se creara despues)
            DashboardController controller = fxmlLoader.getController();
            controller.initData(user);

            // Obtener la ventana (Stage) actual y cambiar su escena
            Stage stage = (Stage) ((Node) event.getSource()).getScene().getWindow();
            stage.setScene(dashboardScene);
            stage.centerOnScreen();
        } catch (IOException e) {
            e.printStackTrace();
            showError("Error al cargar la interfaz principal.");
        }
    }
}
